#!/usr/bin/env python3
"""Architecture Conformance Monitor — auto-generated from SysML v2 model.

System: TestRobot
Generated by: ros2-sysmlv2 bridge pipeline

Structural conformance checks (all via ROS2 graph introspection, no topic
subscriptions required):
  - Node presence and namespace
  - Topic existence and message types
  - Connection endpoint verification (publisher+subscriber on each topic)
  - QoS policy verification per topic endpoint
  - Service endpoint presence
  - Action endpoint presence (via underlying action topics)
  - Parameter declaration presence on custom nodes

Publishes diagnostic_msgs/DiagnosticArray on /conformance_report.
"""
import rclpy
from rclpy.node import Node
from rclpy.qos import QoSReliabilityPolicy, QoSDurabilityPolicy
from diagnostic_msgs.msg import DiagnosticArray, DiagnosticStatus, KeyValue

# ═══════════════════════════════════════════════════════════════
# Expected architecture (embedded from architecture.json)
# ═══════════════════════════════════════════════════════════════

EXPECTED_NODES = {
    ("lidar_driver", "/sensors"),
    ("PlannerServer", "/"),
    ("ControllerServer", "/"),
    ("BtNavigator", "/"),
    ("BehaviorServer", "/"),
    ("SmootherServer", "/"),
    ("Costmap2DROS", "/"),
    ("Costmap2DROS", "/"),
    ("AmclNode", "/"),
    ("Nav2MapServer", "/"),
    ("Nav2VelocitySmoother", "/"),
    ("Nav2CollisionMonitor", "/"),
    ("Nav2LifecycleManager", "/"),
    ("my_controller", "/"),
}

EXPECTED_TOPICS = {
    "/scan": "sensor_msgs.msg.LaserScan",
    "plan": "nav_msgs.msg.Path",
    "cmd_vel": "geometry_msgs.msg.TwistStamped",
    "plan_smoothed": "nav_msgs.msg.Path",
    "costmap": "nav2_msgs.msg.Costmap",
    "published_footprint": "geometry_msgs.msg.PolygonStamped",
    "amcl_pose": "geometry_msgs.msg.PoseWithCovarianceStamped",
    "map": "nav_msgs.msg.OccupancyGrid",
    "cmd_vel_smoothed": "geometry_msgs.msg.Twist",
    "cmd_vel_out": "geometry_msgs.msg.Twist",
    "/cmd_vel": "geometry_msgs.msg.Twist",
}

# Resolved connections: each entry has the topic, publisher node, subscriber
# node, and QoS expectations resolved from the architecture model.
EXPECTED_CONNECTIONS = [
    {
        "name": "lidarToLocalCostmap",
        "topic": "/scan",
        "pub_node": "lidar_driver",
        "pub_namespace": "/sensors",
        "sub_node": "Costmap2DROS",
        "sub_namespace": "/",
        "msg_type": "sensor_msgs.msg.LaserScan",
        "pub_qos": "sensor_data",
        "sub_qos": "",
    },
]

EXPECTED_SERVICES = [
    {"service_name": "map", "node_name": "Nav2MapServer", "namespace": "/"},
    {"service_name": "load_map", "node_name": "Nav2MapServer", "namespace": "/"},
]

EXPECTED_ACTIONS = [
    {"action_name": "compute_path_to_pose", "node_name": "PlannerServer", "namespace": "/"},
    {"action_name": "follow_path", "node_name": "ControllerServer", "namespace": "/"},
    {"action_name": "navigate_to_pose", "node_name": "BtNavigator", "namespace": "/"},
    {"action_name": "spin", "node_name": "BehaviorServer", "namespace": "/"},
    {"action_name": "backup", "node_name": "BehaviorServer", "namespace": "/"},
    {"action_name": "wait", "node_name": "BehaviorServer", "namespace": "/"},
    {"action_name": "smooth_path", "node_name": "SmootherServer", "namespace": "/"},
    {"action_name": "follow_path", "node_name": "my_controller", "namespace": "/"},
]

EXPECTED_PARAMS = [
    {"param_name": "max_velocity", "node_name": "my_controller", "namespace": "/"},
]

EXPECTED_QOS = [
    {"topic": "/scan", "preset": "sensor_data", "reliability": "BEST_EFFORT", "durability": "VOLATILE"},
    {"topic": "map", "preset": "best_available", "reliability": "RELIABLE", "durability": "VOLATILE"},
]

EXPECTED_FRAMES = {
    "map",
    "odom",
    "base_link",
    "map",
    "odom",
    "base_link",
    "lidar_link",
}

CHECK_INTERVAL_SEC = 5.0

# Map model QoS names to rclpy enum values for comparison
_RELIABILITY_MAP = {
    "BEST_EFFORT": QoSReliabilityPolicy.BEST_EFFORT,
    "RELIABLE": QoSReliabilityPolicy.RELIABLE,
}
_DURABILITY_MAP = {
    "VOLATILE": QoSDurabilityPolicy.VOLATILE,
    "TRANSIENT_LOCAL": QoSDurabilityPolicy.TRANSIENT_LOCAL,
}


class ConformanceMonitor(Node):
    """Monitors the running ROS2 graph against the architecture model."""

    def __init__(self):
        super().__init__(node_name='conformance_monitor')
        self.diag_pub = self.create_publisher(
            DiagnosticArray, '/conformance_report', 10)
        self.timer = self.create_timer(CHECK_INTERVAL_SEC, self._check_conformance)
        self.get_logger().info(
            f'Conformance monitor started '
            f'(expecting {len(EXPECTED_NODES)} nodes, '
            f'{len(EXPECTED_TOPICS)} topics, '
            f'{len(EXPECTED_CONNECTIONS)} connections, '
            f'{len(EXPECTED_SERVICES)} services, '
            f'{len(EXPECTED_ACTIONS)} actions)')

    def _check_conformance(self):
        """Run all conformance checks and publish results."""
        diag_array = DiagnosticArray()
        diag_array.header.stamp = self.get_clock().now().to_msg()

        # ── Node presence check ──
        discovered = set(self.get_node_names_and_namespaces())
        node_status = DiagnosticStatus()
        node_status.name = 'node_presence'

        missing = EXPECTED_NODES - discovered
        # Exclude the monitor itself from unexpected detection
        unexpected = discovered - EXPECTED_NODES - {
            ('conformance_monitor', '/'),
        }

        if not missing:
            node_status.level = DiagnosticStatus.OK
            node_status.message = f'All {len(EXPECTED_NODES)} expected nodes present'
        else:
            node_status.level = DiagnosticStatus.ERROR
            node_status.message = f'{len(missing)} nodes missing'
            for name, ns in sorted(missing):
                node_status.values.append(
                    KeyValue(key='missing', value=f'{ns}/{name}'))

        diag_array.status.append(node_status)

        # ── Topic existence + type check ──
        discovered_topics = dict(self.get_topic_names_and_types())
        topic_status = DiagnosticStatus()
        topic_status.name = 'topic_types'

        topic_ok = 0
        topic_missing = 0
        topic_mismatch = 0

        for topic_name, expected_type in EXPECTED_TOPICS.items():
            if topic_name not in discovered_topics:
                topic_missing += 1
                topic_status.values.append(
                    KeyValue(key='missing', value=topic_name))
            else:
                actual_types = discovered_topics[topic_name]
                # ROS2 returns types as list of strings like ['sensor_msgs/msg/LaserScan']
                expected_ros_type = expected_type.replace('.', '/')
                if expected_ros_type in actual_types:
                    topic_ok += 1
                else:
                    topic_mismatch += 1
                    topic_status.values.append(
                        KeyValue(key='type_mismatch',
                                 value=f'{topic_name}: expected {expected_type}, got {actual_types}'))

        if topic_missing == 0 and topic_mismatch == 0:
            topic_status.level = DiagnosticStatus.OK
            topic_status.message = f'All {len(EXPECTED_TOPICS)} topics OK'
        elif topic_mismatch > 0:
            topic_status.level = DiagnosticStatus.ERROR
            topic_status.message = f'{topic_mismatch} type mismatches, {topic_missing} missing'
        else:
            topic_status.level = DiagnosticStatus.WARN
            topic_status.message = f'{topic_missing} topics not yet discovered'

        diag_array.status.append(topic_status)

        # ── Connection endpoint verification ──
        conn_status = DiagnosticStatus()
        conn_status.name = 'connections'
        conn_ok = 0
        conn_fail = 0

        for conn in EXPECTED_CONNECTIONS:
            topic = conn['topic']
            expected_pub = conn['pub_node']
            expected_pub_ns = conn['pub_namespace']
            expected_sub = conn['sub_node']
            expected_sub_ns = conn['sub_namespace']

            # Check publisher endpoint
            pub_found = False
            try:
                pub_infos = self.get_publishers_info_by_topic(topic)
                for info in pub_infos:
                    if (info.node_name == expected_pub and
                            info.node_namespace == expected_pub_ns):
                        pub_found = True
                        break
            except Exception as e:
                self.get_logger().debug(f'Publisher check failed for {topic}: {e}')

            # Check subscriber endpoint
            sub_found = False
            try:
                sub_infos = self.get_subscriptions_info_by_topic(topic)
                for info in sub_infos:
                    if (info.node_name == expected_sub and
                            info.node_namespace == expected_sub_ns):
                        sub_found = True
                        break
            except Exception as e:
                self.get_logger().debug(f'Subscriber check failed for {topic}: {e}')

            if pub_found and sub_found:
                conn_ok += 1
            else:
                conn_fail += 1
                detail_parts = []
                if not pub_found:
                    detail_parts.append(
                        f'pub {expected_pub_ns}/{expected_pub} not on {topic}')
                if not sub_found:
                    detail_parts.append(
                        f'sub {expected_sub_ns}/{expected_sub} not on {topic}')
                conn_status.values.append(
                    KeyValue(key=conn['name'], value='; '.join(detail_parts)))

        if conn_fail == 0 and len(EXPECTED_CONNECTIONS) > 0:
            conn_status.level = DiagnosticStatus.OK
            conn_status.message = f'All {conn_ok} connections verified'
        elif conn_fail > 0:
            conn_status.level = DiagnosticStatus.ERROR
            conn_status.message = f'{conn_fail} connections broken, {conn_ok} OK'
        else:
            conn_status.level = DiagnosticStatus.OK
            conn_status.message = 'No connections to check'

        diag_array.status.append(conn_status)

        # ── QoS policy verification ──
        qos_status = DiagnosticStatus()
        qos_status.name = 'qos_policies'
        qos_ok = 0
        qos_fail = 0

        for qos_entry in EXPECTED_QOS:
            topic = qos_entry['topic']
            expected_rel = _RELIABILITY_MAP.get(qos_entry['reliability'])
            expected_dur = _DURABILITY_MAP.get(qos_entry['durability'])

            if expected_rel is None and expected_dur is None:
                # SYSTEM_DEFAULT or UNKNOWN — skip verification
                qos_ok += 1
                continue

            try:
                pub_infos = self.get_publishers_info_by_topic(topic)
                for info in pub_infos:
                    qp = info.qos_profile
                    problems = []
                    if expected_rel and qp.reliability != expected_rel:
                        problems.append(
                            f'reliability: expected {qos_entry["reliability"]}, '
                            f'got {qp.reliability.name}')
                    if expected_dur and qp.durability != expected_dur:
                        problems.append(
                            f'durability: expected {qos_entry["durability"]}, '
                            f'got {qp.durability.name}')
                    if problems:
                        qos_fail += 1
                        qos_status.values.append(
                            KeyValue(key=topic, value='; '.join(problems)))
                    else:
                        qos_ok += 1
            except Exception as e:
                # Don't count API errors as passing — log and skip
                self.get_logger().debug(f'QoS check skipped for {topic}: {e}')

        if qos_fail == 0:
            qos_status.level = DiagnosticStatus.OK
            qos_status.message = f'{qos_ok} QoS policies OK'
        else:
            qos_status.level = DiagnosticStatus.WARN
            qos_status.message = f'{qos_fail} QoS mismatches, {qos_ok} OK'

        diag_array.status.append(qos_status)

        # ── Service endpoint check ──
        if EXPECTED_SERVICES:
            svc_status = DiagnosticStatus()
            svc_status.name = 'services'
            svc_ok = 0
            svc_missing = 0

            discovered_services = dict(self.get_service_names_and_types())
            for svc in EXPECTED_SERVICES:
                svc_name = svc['service_name']
                ns = svc['namespace']
                # Construct full service name
                full_name = f"{ns.rstrip('/')}/{svc_name}" if ns != '/' else f"/{svc_name}"
                if full_name in discovered_services:
                    svc_ok += 1
                else:
                    svc_missing += 1
                    svc_status.values.append(
                        KeyValue(key='missing', value=full_name))

            if svc_missing == 0:
                svc_status.level = DiagnosticStatus.OK
                svc_status.message = f'All {svc_ok} services present'
            else:
                svc_status.level = DiagnosticStatus.WARN
                svc_status.message = f'{svc_missing} services missing, {svc_ok} present'

            diag_array.status.append(svc_status)

        # ── Action endpoint check ──
        if EXPECTED_ACTIONS:
            act_status = DiagnosticStatus()
            act_status.name = 'actions'
            act_ok = 0
            act_missing = 0

            # Action servers expose underlying topics: <action_name>/_action/send_goal
            for act in EXPECTED_ACTIONS:
                act_name = act['action_name']
                ns = act['namespace']
                full_name = f"{ns.rstrip('/')}/{act_name}" if ns != '/' else f"/{act_name}"
                goal_topic = f"{full_name}/_action/send_goal"
                if goal_topic in discovered_topics:
                    act_ok += 1
                else:
                    act_missing += 1
                    act_status.values.append(
                        KeyValue(key='missing', value=full_name))

            if act_missing == 0:
                act_status.level = DiagnosticStatus.OK
                act_status.message = f'All {act_ok} actions present'
            else:
                act_status.level = DiagnosticStatus.WARN
                act_status.message = f'{act_missing} actions missing, {act_ok} present'

            diag_array.status.append(act_status)

        # ── Parameter declaration check ──
        if EXPECTED_PARAMS:
            param_status = DiagnosticStatus()
            param_status.name = 'parameters'
            param_ok = 0
            param_missing = 0

            for param_entry in EXPECTED_PARAMS:
                pname = param_entry['param_name']
                node_name = param_entry['node_name']
                ns = param_entry['namespace']
                # Attempt to list parameters on the target node
                full_node = f"{ns.rstrip('/')}/{node_name}" if ns != '/' else f"/{node_name}"
                try:
                    # Use service client pattern to check parameter existence
                    # For now, check that the node exists (parameter verification
                    # requires async service calls beyond simple graph introspection)
                    node_found = (node_name, ns) in discovered
                    if node_found:
                        param_ok += 1
                    else:
                        param_missing += 1
                        param_status.values.append(
                            KeyValue(key='missing_node', value=f'{full_node} (param: {pname})'))
                except Exception as e:
                    self.get_logger().debug(f'Parameter check error: {e}')

            if param_missing == 0:
                param_status.level = DiagnosticStatus.OK
                param_status.message = f'{param_ok} parameter declarations OK (node presence verified)'
            else:
                param_status.level = DiagnosticStatus.WARN
                param_status.message = f'{param_missing} parameter nodes missing, {param_ok} OK'

            diag_array.status.append(param_status)

        # ── TF frame check ──
        if EXPECTED_FRAMES:
            frame_status = DiagnosticStatus()
            frame_status.name = 'tf_frames'
            frame_ok = 0
            frame_missing = 0

            # Check if /tf and /tf_static topics exist (frames are published on these)
            tf_topics = set()
            if '/tf' in discovered_topics:
                tf_topics.add('/tf')
            if '/tf_static' in discovered_topics:
                tf_topics.add('/tf_static')

            if tf_topics:
                # TF infrastructure is up — frames are expected to be publishing
                frame_ok = len(EXPECTED_FRAMES)
                frame_status.level = DiagnosticStatus.OK
                frame_status.message = (
                    f'{frame_ok} frames declared, TF topics active '
                    f'({", ".join(sorted(tf_topics))})')
            else:
                frame_missing = len(EXPECTED_FRAMES)
                frame_status.level = DiagnosticStatus.WARN
                frame_status.message = (
                    f'TF topics not found — {frame_missing} frames expected but '
                    f'/tf and /tf_static not active')

            frame_status.values.append(
                KeyValue(key='expected_frames',
                         value=', '.join(sorted(EXPECTED_FRAMES))))
            diag_array.status.append(frame_status)

        # ── Publish and log ──
        self.diag_pub.publish(diag_array)

        levels = {s.level for s in diag_array.status}
        if DiagnosticStatus.ERROR in levels:
            summary = 'FAIL'
        elif DiagnosticStatus.WARN in levels:
            summary = 'WARN'
        else:
            summary = 'OK'

        node_present = len(EXPECTED_NODES) - len(missing)
        self.get_logger().info(
            f'[Conformance {summary}] '
            f'Nodes: {node_present}/{len(EXPECTED_NODES)} | '
            f'Topics: {topic_ok}/{len(EXPECTED_TOPICS)} | '
            f'Connections: {conn_ok}/{len(EXPECTED_CONNECTIONS)} | '
            f'QoS: {qos_ok}/{len(EXPECTED_QOS)}')


def main(args=None):
    rclpy.init(args=args)
    node = ConformanceMonitor()
    rclpy.spin(node)
    node.destroy_node()
    rclpy.shutdown()


if __name__ == '__main__':
    main()
